import mysql.connector

def import_data_to_mysql(file_path, table_name, db_config):
    try:
        # Enable local_infile in the connection
        db_config['allow_local_infile'] = True
        
        # Establish the database connection
        connection = mysql.connector.connect(**db_config)
        cursor = connection.cursor()

        # Construct the LOAD DATA INFILE SQL statement
        load_data_sql = "LOAD DATA INFILE '{}' INTO TABLE {}".format(file_path, table_name)

        # Execute the SQL statement
        cursor.execute(load_data_sql)
        connection.commit()

        print("Data imported successfully from {} to table {}".format(file_path, table_name))

    except mysql.connector.Error as err:
        print("Error: {}".format(err))
    finally:
        if connection.is_connected():
            cursor.close()
            connection.close()

